 4→import android.net.Uri
 5→import android.os.Bundle
 6→import androidx.activity.enableEdgeToEdge
 7→import app.k9mail.core.ui.compose.common.activity.setActivityContent
 8→import app.k9mail.core.ui.theme.api.FeatureThemeProvider
 9→import com.fsck.k9.ui.base.K9Activity
10→import org.koin.android.ext.android.inject
11→
12→class QrCodeScannerActivity : K9Activity() {
13→    private val themeProvider: FeatureThemeProvider by inject()
14→
15→    override fun onCreate(savedInstanceState: Bundle?) {
16→        super.onCreate(savedInstanceState)
17→
18→        enableEdgeToEdge()
19→
20→        setActivityContent {
21→            themeProvider.WithTheme(darkTheme = true) {
22→                QrCodeScannerScreen(
23→                    finishWithResult = ::finishWithResult,
24→                    finish = ::finish,
25→                )
26→            }
27→        }
28→    }
29→
30→    private fun finishWithResult(result: Uri) {
31→        val resultIntent = Intent().apply {
32→            data = result
33→        }
34→        setResult(RESULT_OK, resultIntent)
35→
36→        finish()
37→    }
38→}
