import androidx.activity.compose.LocalActivity
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.safeDrawingPadding
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.compose.rememberNavController
import app.k9mail.core.ui.compose.designsystem.atom.Surface
import app.k9mail.core.ui.theme.api.FeatureThemeProvider
import app.k9mail.feature.launcher.navigation.FeatureLauncherNavHost
import org.koin.compose.koinInject

@Composable
fun FeatureLauncherApp(
    modifier: Modifier = Modifier,
    themeProvider: FeatureThemeProvider = koinInject<FeatureThemeProvider>(),
) {
    val navController = rememberNavController()

    themeProvider.WithTheme {
        Surface(
            modifier = Modifier
                .fillMaxSize()
                .safeDrawingPadding()
                .then(modifier),
        ) {
            val activity = LocalActivity.current

            FeatureLauncherNavHost(
                navController = navController,
                onBack = { activity.finish() },
            )
        }
    }
}"}

{"file_path":"/project/feature/settings/import/src/main/kotlin/app/k9mail/feature/settings/import/ui/SettingsImportScreen.kt","content":"package app.k9mail.feature.settings.import.ui

import android.os.Bundle
import androidx.activity.compose.LocalActivity
import androidx.compose.foundation.layout.PaddingValues
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.padding
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.stringResource
import androidx.fragment.app.FragmentActivity
import androidx.fragment.compose.AndroidFragment
import androidx.lifecycle.compose.LocalLifecycleOwner
import app.k9mail.core.ui.compose.designsystem.atom.button.ButtonIcon
import app.k9mail.core.ui.compose.designsystem.atom.icon.Icons
import app.k9mail.core.ui.compose.designsystem.organism.TopAppBar
import app.k9mail.core.ui.compose.designsystem.template.Scaffold
import app.k9mail.feature.settings.importing.R

@Composable
fun SettingsImportScreen(
    action: SettingsImportAction,
    onImportSuccess: () -> Unit,
    onBack: () -> Unit,
    modifier: Modifier = Modifier,
) {
    Scaffold(
        topBar = {
            TopAppBar(
                title = stringResource(R.string.settings_import_title),
                navigationIcon = {
                    ButtonIcon(
                        onClick = onBack,
                        imageVector = Icons.Outlined.ArrowBack,
                        contentDescription = stringResource(androidx.appcompat.R.string.abc_action_bar_up_description),
                    )
                },
            )
        },
        modifier = modifier,
    ) { innerPadding ->
        SettingsImportContent(action, onImportSuccess, onBack, innerPadding)
    }
}

@Composable
private fun SettingsImportContent(
    action: SettingsImportAction,
    onImportSuccess: () -> Unit,
    onBack: () -> Unit,
    paddingValues: PaddingValues,
) {
    val activity = LocalActivity.current as FragmentActivity

    activity.supportFragmentManager.setFragmentResultListener(
        SettingsImportFragment.FRAGMENT_RESULT_KEY,
        LocalLifecycleOwner.current,
    ) { _, result: Bundle ->
        if (result.getBoolean(SettingsImportFragment.FRAGMENT_RESULT_ACCOUNT_IMPORTED, false)) {
            onImportSuccess()
        } else {
            onBack()
        }
    }

    AndroidFragment<SettingsImportFragment>(
        arguments = action.toBundle(),
        modifier = Modifier
            .fillMaxSize()
            .padding(paddingValues),
    )
}"}

